INSERT INTO `v1_f90c37fe34bf0a26b2614e3c263626d5c7d96c2a64999980d279965eb8cbddaf` VALUES (0, 60004, 0, 1, 569, 2, 0, 4, "", "", 0, "今日の運勢は小吉！　気の向くままに過ごすのが幸せへの近道！　美味い魚を食べて猫を眺めて、自然体で過ごすのはどうだい？");
